131→#[cfg(test)]
132→mod tests {
133→    use super::*;
134→    use aios_protocol::event::*;
135→    use std::collections::HashMap;
136→
137→    /// Install a minimal subscriber so spans are not disabled during tests.
138→    /// Uses `try_init` to tolerate tests running in any order.
